import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { Link, useLocation } from "react-router-dom";
import BusCard from "../components/BusCard";
import { Bus } from "../types";

const API_BASE = "http://localhost:5000/api";

type TimeFilter = "all" | "morning" | "evening";
type SortOption = "price" | "departure" | "arrival" | "rating";

const getHour = (dateString: string) => new Date(dateString).getHours();

const BusList: React.FC = () => {
  const [buses, setBuses] = useState<Bus[]>([]);
  const [loading, setLoading] = useState(true);
  const [timeFilter, setTimeFilter] = useState<TimeFilter>("all");
  const [sortBy, setSortBy] = useState<SortOption>("departure");
  const [maxPrice, setMaxPrice] = useState(2000);
  const [onlyAC, setOnlyAC] = useState(false);
  const [onlyNonAC, setOnlyNonAC] = useState(false);
  const [seatType, setSeatType] = useState("all");
  const [onlyHighRated, setOnlyHighRated] = useState(false);
  const [operator, setOperator] = useState("all");
  const location = useLocation();

  const searchInfo = useMemo(() => {
    const params = new URLSearchParams(location.search);
    return {
      departureCity: params.get("departureCity") || "",
      arrivalCity: params.get("arrivalCity") || "",
      date: params.get("date") || ""
    };
  }, [location.search]);

  useEffect(() => {
    const fetchBuses = async () => {
      try {
        setLoading(true);
        const params = new URLSearchParams();
        if (searchInfo.departureCity) params.append("departureCity", searchInfo.departureCity);
        if (searchInfo.arrivalCity) params.append("arrivalCity", searchInfo.arrivalCity);

        if (searchInfo.date) params.append("date", searchInfo.date);
        const response = await axios.get<Bus[]>(`${API_BASE}/buses?${params.toString()}`);
        setBuses(response.data);
      } catch (error) {
        console.error("Failed to fetch buses", error);
      } finally {
        setLoading(false);
      }
    };

    fetchBuses();
  }, [searchInfo.departureCity, searchInfo.arrivalCity, searchInfo.date]);

  const operators = useMemo(() => {
    return Array.from(new Set(buses.map((bus) => bus.operatorName))).sort();
  }, [buses]);

  const maxAvailablePrice = useMemo(() => {
    return buses.length ? Math.max(...buses.map((bus) => bus.price)) : 2000;
  }, [buses]);

  useEffect(() => {
    setMaxPrice(maxAvailablePrice);
  }, [maxAvailablePrice]);

  const filteredBuses = useMemo(() => {
    return buses
      .filter((bus) => {
        if (timeFilter === "morning") {
          const hour = getHour(bus.departureTime);
          if (hour < 5 || hour >= 12) return false;
        }

        if (timeFilter === "evening") {
          const hour = getHour(bus.departureTime);
          if (hour < 17 || hour >= 24) return false;
        }

        if (bus.price > maxPrice) return false;
        if (onlyAC && !bus.isAC) return false;
        if (onlyNonAC && bus.isAC) return false;
        if (seatType !== "all" && bus.seatType !== seatType) return false;
        if (onlyHighRated && bus.rating < 4) return false;
        if (operator !== "all" && bus.operatorName !== operator) return false;
        return true;
      })
      .sort((left, right) => {
        if (sortBy === "price") return left.price - right.price;
        if (sortBy === "departure") return new Date(left.departureTime).getTime() - new Date(right.departureTime).getTime();
        if (sortBy === "arrival") return new Date(left.arrivalTime).getTime() - new Date(right.arrivalTime).getTime();
        return right.rating - left.rating;
      });
  }, [buses, maxPrice, onlyAC, onlyHighRated, onlyNonAC, operator, seatType, sortBy, timeFilter]);

  const quickStats = useMemo(() => {
    const morning = buses.filter((bus) => {
      const hour = getHour(bus.departureTime);
      return hour >= 5 && hour < 12;
    }).length;

    const evening = buses.filter((bus) => {
      const hour = getHour(bus.departureTime);
      return hour >= 17 && hour < 24;
    }).length;

    return {
      total: buses.length,
      morning,
      evening
    };
  }, [buses]);

  const filterBtnClass = (value: TimeFilter) =>
    `rounded-lg px-4 py-2 text-sm font-semibold transition ${
      timeFilter === value ? "bg-blue-600 text-white" : "border border-slate-300 text-slate-700 hover:bg-slate-100"
    }`;

  return (
    <section className="space-y-6">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Available Buses</h2>
          <p className="text-sm text-slate-600">
            {searchInfo.departureCity || "All cities"} {" -> "} {searchInfo.arrivalCity || "All cities"}
            {searchInfo.date ? ` | ${searchInfo.date}` : ""}
          </p>
        </div>
        <Link to="/" className="rounded-lg border border-slate-300 px-4 py-2 text-sm font-semibold text-slate-700 hover:bg-slate-100">
          Modify Search
        </Link>
      </div>

      <div className="grid gap-3 sm:grid-cols-3">
        <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Total Buses</p>
          <p className="mt-1 text-2xl font-bold text-slate-900">{quickStats.total}</p>
        </div>
        <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Morning</p>
          <p className="mt-1 text-2xl font-bold text-slate-900">{quickStats.morning}</p>
        </div>
        <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Evening</p>
          <p className="mt-1 text-2xl font-bold text-slate-900">{quickStats.evening}</p>
        </div>
      </div>

      <div className="grid gap-6 lg:grid-cols-[320px_1fr]">
        <aside className="rounded-2xl bg-white p-5 shadow-travel ring-1 ring-slate-200">
          <div className="flex items-center justify-between">
            <h3 className="text-lg font-semibold text-slate-900">Filters</h3>
            <button
              type="button"
              onClick={() => {
                setTimeFilter("all");
                setSortBy("departure");
                setMaxPrice(maxAvailablePrice);
                setOnlyAC(false);
                setOnlyNonAC(false);
                setSeatType("all");
                setOnlyHighRated(false);
                setOperator("all");
              }}
              className="text-xs font-semibold text-blue-600"
            >
              Reset
            </button>
          </div>

          <div className="mt-5 space-y-5 text-sm text-slate-700">
            <div>
              <p className="font-semibold text-slate-900">Time</p>
              <div className="mt-3 flex flex-wrap gap-2">
                <button type="button" className={filterBtnClass("all")} onClick={() => setTimeFilter("all")}>All</button>
                <button type="button" className={filterBtnClass("morning")} onClick={() => setTimeFilter("morning")}>Morning</button>
                <button type="button" className={filterBtnClass("evening")} onClick={() => setTimeFilter("evening")}>Evening</button>
              </div>
            </div>

            <div>
              <label className="font-semibold text-slate-900">Price Range</label>
              <input
                type="range"
                min={300}
                max={Math.max(maxAvailablePrice, 300)}
                step={50}
                value={Math.min(maxPrice, Math.max(maxAvailablePrice, 300))}
                onChange={(e) => setMaxPrice(Number(e.target.value))}
                className="mt-3 w-full"
              />
              <p className="mt-1 text-xs text-slate-500">Up to INR {maxPrice}</p>
            </div>

            <div>
              <p className="font-semibold text-slate-900">Bus Type</p>
              <div className="mt-3 space-y-2">
                <label className="flex items-center gap-2"><input type="checkbox" checked={onlyAC} onChange={(e) => setOnlyAC(e.target.checked)} /> AC</label>
                <label className="flex items-center gap-2"><input type="checkbox" checked={onlyNonAC} onChange={(e) => setOnlyNonAC(e.target.checked)} /> Non AC</label>
              </div>
            </div>

            <div>
              <label className="font-semibold text-slate-900">Seat Type</label>
              <select value={seatType} onChange={(e) => setSeatType(e.target.value)} className="mt-2 w-full rounded-lg border border-slate-300 px-3 py-2">
                <option value="all">All</option>
                <option value="Seater">Seater</option>
                <option value="Sleeper">Sleeper</option>
              </select>
            </div>

            <div>
              <label className="flex items-center gap-2 font-semibold text-slate-900">
                <input type="checkbox" checked={onlyHighRated} onChange={(e) => setOnlyHighRated(e.target.checked)} /> Rating 4+
              </label>
            </div>

            <div>
              <label className="font-semibold text-slate-900">Bus Operator</label>
              <select value={operator} onChange={(e) => setOperator(e.target.value)} className="mt-2 w-full rounded-lg border border-slate-300 px-3 py-2">
                <option value="all">All Operators</option>
                {operators.map((item) => (
                  <option key={item} value={item}>{item}</option>
                ))}
              </select>
            </div>
          </div>
        </aside>

        <div className="space-y-5">
          <div className="rounded-2xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
            <div className="flex flex-wrap items-center justify-between gap-3">
              <p className="text-sm font-semibold text-slate-700">{filteredBuses.length} buses available after filters</p>
              <label className="flex items-center gap-2 text-sm text-slate-600">
                Sort by
                <select value={sortBy} onChange={(e) => setSortBy(e.target.value as SortOption)} className="rounded-lg border border-slate-300 px-3 py-2 text-sm">
                  <option value="price">Price (Low to High)</option>
                  <option value="departure">Departure Time</option>
                  <option value="arrival">Arrival Time</option>
                  <option value="rating">Rating</option>
                </select>
              </label>
            </div>
          </div>

          {loading ? <p className="text-slate-600">Loading buses...</p> : null}
          {!loading && filteredBuses.length === 0 ? (
            <div className="rounded-xl bg-white p-6 text-center text-slate-600 shadow-travel ring-1 ring-slate-200">
              No buses found for the selected filters.
            </div>
          ) : null}

          <div className="grid gap-4 xl:grid-cols-2">
            {filteredBuses.map((bus) => (
              <BusCard key={bus.id} bus={bus} travelDate={searchInfo.date} />
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default BusList;
